def solve() -> None:
    import sys
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    results = []
    for i in range(1, t + 1):
        s = data[i]
        if s == "abc":
            results.append("YES")
        elif s[0] == 'a' or s[1] == 'b' or s[2] == 'c':
            # If any card is already in its correct position,
            # one swap can fix the rest.
            results.append("YES")
        else:
            results.append("NO")
    sys.stdout.write("\n".join(results))

if __name__ == "__main__":
    solve()
